#![allow(clippy::needless_range_loop)]

//! Comprehensive tests for `BuildStats` generated by adze-tool.
//!
//! Covers: direct construction, Debug formatting, stats from the build
//! pipeline, grammar-complexity correlation, conflict counting, comparison
//! between grammars, zero-complexity grammars, large grammars, BuildResult
//! fields, GrammarBuilder-based grammars, BuildOptions defaults/customization,
//! and pipeline determinism.

use std::fs;

use adze_ir::builder::GrammarBuilder;
use adze_ir::{
    Associativity, Grammar, PrecedenceKind, ProductionId, Rule, Symbol, SymbolId, Token,
    TokenPattern,
};
use adze_tool::pure_rust_builder::{BuildOptions, BuildResult, BuildStats, build_parser};
use tempfile::TempDir;

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/// Build options writing into a fresh temp directory.
fn temp_opts() -> (TempDir, BuildOptions) {
    let dir = TempDir::new().unwrap();
    let opts = BuildOptions {
        out_dir: dir.path().to_string_lossy().into(),
        emit_artifacts: false,
        compress_tables: false,
    };
    (dir, opts)
}

/// Minimal grammar: one token, one non-terminal with a single production.
fn minimal_grammar(name: &str) -> Grammar {
    let mut g = Grammar::new(name.to_string());
    let tok = SymbolId(1);
    let src = SymbolId(2);
    g.tokens.insert(
        tok,
        Token {
            name: "number".into(),
            pattern: TokenPattern::Regex(r"\d+".into()),
            fragile: false,
        },
    );
    g.rule_names.insert(src, "source_file".into());
    g.rules.entry(src).or_default().push(Rule {
        lhs: src,
        rhs: vec![Symbol::Terminal(tok)],
        precedence: None,
        associativity: None,
        fields: vec![],
        production_id: ProductionId(0),
    });
    g
}

/// Build a grammar and return the BuildResult.
fn build(g: Grammar) -> BuildResult {
    let (_dir, opts) = temp_opts();
    build_parser(g, opts).expect("build should succeed")
}

/// Build a grammar and return just the stats.
fn stats_for(g: Grammar) -> BuildStats {
    build(g).build_stats
}

/// Build a GrammarBuilder grammar and return the BuildResult.
fn build_from_builder(gb: GrammarBuilder) -> BuildResult {
    let (_dir, opts) = temp_opts();
    build_parser(gb.build(), opts).expect("build should succeed")
}

/// Build grammar.js through the pure-Rust builder and return the result.
fn build_js(js: &str) -> BuildResult {
    let dir = TempDir::new().unwrap();
    let path = dir.path().join("grammar.js");
    fs::write(&path, js).unwrap();
    let opts = BuildOptions {
        out_dir: dir.path().to_string_lossy().into(),
        emit_artifacts: false,
        compress_tables: false,
    };
    adze_tool::pure_rust_builder::build_parser_from_grammar_js(&path, opts).unwrap()
}

// =========================================================================
// 1. BuildStats direct construction
// =========================================================================

#[test]
fn direct_construction_zero_values() {
    let s = BuildStats {
        state_count: 0,
        symbol_count: 0,
        conflict_cells: 0,
    };
    assert_eq!(s.state_count, 0);
    assert_eq!(s.symbol_count, 0);
    assert_eq!(s.conflict_cells, 0);
}

#[test]
fn direct_construction_nonzero_values() {
    let s = BuildStats {
        state_count: 42,
        symbol_count: 10,
        conflict_cells: 3,
    };
    assert_eq!(s.state_count, 42);
    assert_eq!(s.symbol_count, 10);
    assert_eq!(s.conflict_cells, 3);
}

#[test]
fn direct_construction_large_values() {
    let s = BuildStats {
        state_count: 100_000,
        symbol_count: 50_000,
        conflict_cells: 25_000,
    };
    assert_eq!(s.state_count, 100_000);
    assert_eq!(s.symbol_count, 50_000);
    assert_eq!(s.conflict_cells, 25_000);
}

