#[test]
fn debug_format_contains_field_names() {
    let s = BuildStats {
        state_count: 5,
        symbol_count: 3,
        conflict_cells: 1,
    };
    let dbg = format!("{:?}", s);
    assert!(dbg.contains("state_count"));
    assert!(dbg.contains("symbol_count"));
    assert!(dbg.contains("conflict_cells"));
}

#[test]
fn debug_format_contains_values() {
    let s = BuildStats {
        state_count: 7,
        symbol_count: 4,
        conflict_cells: 2,
    };
    let dbg = format!("{:?}", s);
    assert!(dbg.contains("7"), "debug should contain state_count value");
    assert!(dbg.contains("4"), "debug should contain symbol_count value");
    assert!(
        dbg.contains("2"),
        "debug should contain conflict_cells value"
    );
}

#[test]
fn debug_format_zero_stats() {
    let s = BuildStats {
        state_count: 0,
        symbol_count: 0,
        conflict_cells: 0,
    };
    let dbg = format!("{:?}", s);
    assert!(!dbg.is_empty());
    // All zeros should still print the struct name
    assert!(dbg.contains("BuildStats"));
}

