// =========================================================================
// 4. Symbol count includes terminals and non-terminals
// =========================================================================

#[test]
fn symbol_count_grows_with_tokens() {
    let s1 = stats_for(minimal_grammar("sym1"));

    // Build a grammar with an extra token
    let mut g = minimal_grammar("sym2");
    let extra_tok = SymbolId(10);
    g.tokens.insert(
        extra_tok,
        Token {
            name: "ident".into(),
            pattern: TokenPattern::Regex(r"[a-z]+".into()),
            fragile: false,
        },
    );
    // Add a rule using the new token so it's reachable
    let src = SymbolId(2);
    g.rules.entry(src).or_default().push(Rule {
        lhs: src,
        rhs: vec![Symbol::Terminal(extra_tok)],
        precedence: None,
        associativity: None,
        fields: vec![],
        production_id: ProductionId(1),
    });
    let s2 = stats_for(g);

    assert!(
        s2.symbol_count >= s1.symbol_count,
        "more tokens should yield at least as many symbols: {} vs {}",
        s2.symbol_count,
        s1.symbol_count,
    );
}

#[test]
fn symbol_count_grows_with_nonterminals() {
    let s1 = stats_for(minimal_grammar("nt1"));

    let mut g = minimal_grammar("nt2");
    let extra_nt = SymbolId(20);
    let tok = SymbolId(1);
    g.rule_names.insert(extra_nt, "extra_rule".into());
    g.rules.entry(extra_nt).or_default().push(Rule {
        lhs: extra_nt,
        rhs: vec![Symbol::Terminal(tok)],
        precedence: None,
        associativity: None,
        fields: vec![],
        production_id: ProductionId(10),
    });
    // Wire extra_nt into source_file so it is reachable
    let src = SymbolId(2);
    g.rules.entry(src).or_default().push(Rule {
        lhs: src,
        rhs: vec![Symbol::NonTerminal(extra_nt)],
        precedence: None,
        associativity: None,
        fields: vec![],
        production_id: ProductionId(11),
    });
    let s2 = stats_for(g);

    assert!(
        s2.symbol_count >= s1.symbol_count,
        "extra non-terminal should not shrink symbol count: {} vs {}",
        s2.symbol_count,
        s1.symbol_count,
    );
}

