#[test]
fn more_rules_yield_at_least_as_many_states() {
    let s_small = stats_for(minimal_grammar("st_small"));

    let mut g = minimal_grammar("st_big");
    let extra_tok = SymbolId(30);
    g.tokens.insert(
        extra_tok,
        Token {
            name: "ident".into(),
            pattern: TokenPattern::Regex(r"[a-z]+".into()),
            fragile: false,
        },
    );
    let src = SymbolId(2);
    g.rules.entry(src).or_default().push(Rule {
        lhs: src,
        rhs: vec![Symbol::Terminal(extra_tok)],
        precedence: None,
        associativity: None,
        fields: vec![],
        production_id: ProductionId(5),
    });
    let s_big = stats_for(g);

    assert!(
        s_big.state_count >= s_small.state_count,
        "bigger grammar should not have fewer states: {} vs {}",
        s_big.state_count,
        s_small.state_count,
    );
}

// =========================================================================
// 6. Conflict cell counting
// =========================================================================

#[test]
fn ambiguous_grammar_has_conflicts() {
    // expr -> expr "+" expr  (left-recursive, ambiguous without precedence)
    let mut g = Grammar::new("ambig".to_string());
    let num = SymbolId(1);
    let plus = SymbolId(3);
    let expr = SymbolId(4);

    g.tokens.insert(
        num,
        Token {
            name: "number".into(),
            pattern: TokenPattern::Regex(r"\d+".into()),
            fragile: false,
        },
    );
    g.tokens.insert(
        plus,
        Token {
            name: "plus".into(),
            pattern: TokenPattern::String("+".into()),
            fragile: false,
        },
    );
    g.rule_names.insert(expr, "source_file".into());

    // expr -> number
    g.rules.entry(expr).or_default().push(Rule {
        lhs: expr,
        rhs: vec![Symbol::Terminal(num)],
        precedence: None,
        associativity: None,
        fields: vec![],
        production_id: ProductionId(0),
    });
    // expr -> expr + expr  (intentionally ambiguous)
    g.rules.entry(expr).or_default().push(Rule {
        lhs: expr,
        rhs: vec![
            Symbol::NonTerminal(expr),
            Symbol::Terminal(plus),
            Symbol::NonTerminal(expr),
        ],
        precedence: None,
        associativity: None,
        fields: vec![],
        production_id: ProductionId(1),
    });

    let s = stats_for(g);
    // GLR builder should detect the shift/reduce ambiguity
    assert!(
        s.conflict_cells > 0,
        "ambiguous grammar without precedence should have conflict cells, got {}",
        s.conflict_cells,
    );
}

#[test]
fn unambiguous_grammar_has_few_conflicts() {
    let s = stats_for(minimal_grammar("unamb"));
    assert!(
        s.conflict_cells <= 2,
        "unambiguous grammar should have at most 2 conflict cells, got {}",
        s.conflict_cells,
    );
}

#[test]
fn precedence_can_reduce_conflicts() {
    // Build two grammars: one with precedence, one without
    let make = |name: &str, prec: bool| -> Grammar {
        let mut g = Grammar::new(name.to_string());
        let num = SymbolId(1);
        let plus = SymbolId(3);
        let expr = SymbolId(4);

        g.tokens.insert(
            num,
            Token {
                name: "number".into(),
                pattern: TokenPattern::Regex(r"\d+".into()),
                fragile: false,
            },
        );
        g.tokens.insert(
            plus,
            Token {
                name: "plus".into(),
                pattern: TokenPattern::String("+".into()),
                fragile: false,
            },
        );
        g.rule_names.insert(expr, "source_file".into());
        g.rules.entry(expr).or_default().push(Rule {
            lhs: expr,
            rhs: vec![Symbol::Terminal(num)],
            precedence: None,
            associativity: None,
            fields: vec![],
            production_id: ProductionId(0),
        });
        g.rules.entry(expr).or_default().push(Rule {
            lhs: expr,
            rhs: vec![
                Symbol::NonTerminal(expr),
                Symbol::Terminal(plus),
                Symbol::NonTerminal(expr),
            ],
            precedence: if prec {
                Some(PrecedenceKind::Static(1))
            } else {
                None
            },
            associativity: if prec {
                Some(Associativity::Left)
            } else {
                None
            },
            fields: vec![],
            production_id: ProductionId(1),
        });
        g
    };

    let s_prec = stats_for(make("prec_yes", true));
    let s_noprec = stats_for(make("prec_no", false));

    // With precedence the builder may still keep Fork actions, but
    // conflict_cells should be <= the unresolved case.
    assert!(
        s_prec.conflict_cells <= s_noprec.conflict_cells,
        "precedence should not increase conflicts: with={} without={}",
        s_prec.conflict_cells,
        s_noprec.conflict_cells,
    );
}

