// =========================================================================
// 9. Large grammar stats (via grammar.js)
// =========================================================================

#[test]
fn large_grammar_has_many_states() {
    let mut rules = String::from("source: $ => choice(\n");
    for i in 0..20 {
        if i > 0 {
            rules.push_str(",\n");
        }
        rules.push_str(&format!("      $.r_{i}"));
    }
    rules.push_str("\n    )");
    for i in 0..20 {
        rules.push_str(&format!(",\n    r_{i}: $ => /tok{i}/"));
    }
    let js = format!("module.exports = grammar({{ name: 'big', rules: {{ {rules} }} }});");
    let r = build_js(&js);
    assert!(
        r.build_stats.state_count > 2,
        "large grammar should have more than 2 states, got {}",
        r.build_stats.state_count,
    );
}

#[test]
fn large_grammar_has_many_symbols() {
    let mut rules = String::from("source: $ => choice(\n");
    for i in 0..20 {
        if i > 0 {
            rules.push_str(",\n");
        }
        rules.push_str(&format!("      $.r_{i}"));
    }
    rules.push_str("\n    )");
    for i in 0..20 {
        rules.push_str(&format!(",\n    r_{i}: $ => /tok{i}/"));
    }
    let js = format!("module.exports = grammar({{ name: 'bigsym', rules: {{ {rules} }} }});");
    let r = build_js(&js);
    // 20 tokens + 21 non-terminals (source + r_0..r_19) + EOF
    assert!(
        r.build_stats.symbol_count >= 20,
        "large grammar should have >= 20 symbols, got {}",
        r.build_stats.symbol_count,
    );
}

#[test]
fn large_grammar_scales_relative_to_small() {
    let s_small = stats_for(minimal_grammar("scale_sm"));

    let mut rules = String::from("source: $ => choice(\n");
    for i in 0..15 {
        if i > 0 {
            rules.push_str(",\n");
        }
        rules.push_str(&format!("      $.r_{i}"));
    }
    rules.push_str("\n    )");
    for i in 0..15 {
        rules.push_str(&format!(",\n    r_{i}: $ => /tok{i}/"));
    }
    let js = format!("module.exports = grammar({{ name: 'scale_lg', rules: {{ {rules} }} }});");
    let r_large = build_js(&js);

    assert!(
        r_large.build_stats.symbol_count > s_small.symbol_count,
        "large grammar should have strictly more symbols than minimal"
    );
    assert!(
        r_large.build_stats.state_count > s_small.state_count,
        "large grammar should have strictly more states than minimal"
    );
}

