// =========================================================================
// 11. Stats with compression vs without
// =========================================================================

#[test]
fn compressed_and_uncompressed_yield_same_stats() {
    let g1 = minimal_grammar("comp_on");
    let g2 = minimal_grammar("comp_off");

    let dir1 = TempDir::new().unwrap();
    let opts1 = BuildOptions {
        out_dir: dir1.path().to_string_lossy().into(),
        emit_artifacts: false,
        compress_tables: true,
    };
    let r1 = build_parser(g1, opts1).unwrap();

    let dir2 = TempDir::new().unwrap();
    let opts2 = BuildOptions {
        out_dir: dir2.path().to_string_lossy().into(),
        emit_artifacts: false,
        compress_tables: false,
    };
    let r2 = build_parser(g2, opts2).unwrap();

    // Stats come from the parse table before compression, so they should match
    assert_eq!(r1.build_stats.state_count, r2.build_stats.state_count);
    assert_eq!(r1.build_stats.symbol_count, r2.build_stats.symbol_count);
    assert_eq!(r1.build_stats.conflict_cells, r2.build_stats.conflict_cells);
}

// =========================================================================
// 12. Multiple-alternative grammar stats
// =========================================================================

#[test]
fn grammar_with_many_alternatives() {
    let mut g = Grammar::new("multi_alt".to_string());
    let src = SymbolId(100);
    g.rule_names.insert(src, "source_file".into());

    for i in 0..10 {
        let tok_id = SymbolId(i + 1);
        g.tokens.insert(
            tok_id,
            Token {
                name: format!("tok_{i}"),
                pattern: TokenPattern::Regex(format!("t{i}")),
                fragile: false,
            },
        );
        g.rules.entry(src).or_default().push(Rule {
            lhs: src,
            rhs: vec![Symbol::Terminal(tok_id)],
            precedence: None,
            associativity: None,
            fields: vec![],
            production_id: ProductionId(i as u16),
        });
    }

    let s = stats_for(g);
    // 10 tokens + at least source_file + EOF
    assert!(
        s.symbol_count >= 12,
        "10-alternative grammar should have >= 12 symbols, got {}",
        s.symbol_count,
    );
    assert!(s.state_count > 0);
}

// =========================================================================
// 13. Grammar with chained non-terminals
// =========================================================================

#[test]
fn chained_nonterminals_increase_state_count() {
    // A -> B, B -> C, C -> tok
    let mut g = Grammar::new("chain".to_string());
    let tok = SymbolId(1);
    let a = SymbolId(10);
    let b = SymbolId(11);
    let c = SymbolId(12);

    g.tokens.insert(
        tok,
        Token {
            name: "x".into(),
            pattern: TokenPattern::String("x".into()),
            fragile: false,
        },
    );
    g.rule_names.insert(a, "source_file".into());
    g.rule_names.insert(b, "b".into());
    g.rule_names.insert(c, "c".into());

    g.rules.entry(a).or_default().push(Rule {
        lhs: a,
        rhs: vec![Symbol::NonTerminal(b)],
        precedence: None,
        associativity: None,
        fields: vec![],
        production_id: ProductionId(0),
    });
    g.rules.entry(b).or_default().push(Rule {
        lhs: b,
        rhs: vec![Symbol::NonTerminal(c)],
        precedence: None,
        associativity: None,
        fields: vec![],
        production_id: ProductionId(1),
    });
    g.rules.entry(c).or_default().push(Rule {
        lhs: c,
        rhs: vec![Symbol::Terminal(tok)],
        precedence: None,
        associativity: None,
        fields: vec![],
        production_id: ProductionId(2),
    });

    let s_chain = stats_for(g);
    let s_min = stats_for(minimal_grammar("chain_base"));

    assert!(
        s_chain.state_count >= s_min.state_count,
        "chained grammar should have at least as many states: {} vs {}",
        s_chain.state_count,
        s_min.state_count,
    );
    // Chain adds 2 extra non-terminals
    assert!(
        s_chain.symbol_count >= s_min.symbol_count,
        "chained grammar should have more symbols: {} vs {}",
        s_chain.symbol_count,
        s_min.symbol_count,
    );
}

